_icao'])?></td><td><?=e($f['age']?:'—')?></td><td><?=e($f['country_code'])?></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="empty-state"><h3>No linked aircraft yet</h3><p>The aircraft CSVs do not include a matching operator record for this airline yet.</p></div><?php endif;?><section class="section-head"><div><div class="eyebrow">Network linkage</div><h2>Destinations</h2></div><p>Destination rows matched by airline name, IATA or ICAO code.</p></section><?php if($dests):?><div class="table-wrap"><table class="mini-table"><thead><tr><th>City</th><th>Airport</th><th>Codes</th><th>Country</th><th>Hub</th></tr></thead><tbody><?php foreach($dests as $d):?><tr><td><?=e($d['city'])?></td><td><?=e($d['airport_name'])?></td><td><?=e(trim(($d['iata_code']?:'').' '.($d['icao_code']?:'')))?></td><td><?=e($d['country'])?></td><td><?=e($d['hub']?:'—')?></td></tr><?php endforeach;?></tbody></table></div><?php else:?><div class="empty-state"><h3>No linked destinations yet</h3><p>Destination rows are available for selected airlines only in the current source files.</p></div><?php endif;?></section><?php endif;?>
