<?php elseif($page==='aircraft'):$q=getv('q');$country=getv('country','all');$type=getv('type','all');$per=60;$offset=(page_num()-1)*$per;$where=[];$params=[];if($country!=='all'){$where[]='country_code=?';$params[]=$country;}if($type!=='all'){$where[]='aircraft_type=?';$params[]=$type;}if($q!==''){$where[]='(registration LIKE ? OR aircraft_type LIKE ? OR icao_code LIKE ? OR operator_name LIKE ? OR operator_icao LIKE ?)';for($i=0;$i<5;$i++)$params[]='%'.$q.'%';}$w=$where?'WHERE '.implode(' AND ',$where):'';$total=(int)scalar("SELECT COUNT(*) FROM aircraft_registrations $w",$params);$list=rows("SELECT * FROM aircraft_registrations $w ORDER BY aircraft_type, registration LIMIT $per OFFSET $offset",$params);$types=rows("SELECT DISTINCT aircraft_type value, aircraft_type label FROM aircraft_registrations WHERE aircraft_type IS NOT NULL AND aircraft_type <> '' ORDER BY aircraft_type LIMIT 500");?><section class="view"><section class="section-head"><div><div class="eyebrow">Aircraft register</div><h2>Aircraft</h2></div><p>Search aircraft registrations by mark, type, airline/operator code, country or source operator name.</p></section><div class="filters panel"><form method="get"><input type="hidden" name="page" value="aircraft"><input name="q" value="<?=e($q)?>" placeholder="Search registration, type, operator…"><select name="country" data-auto-submit><?=option_tags(country_options(),$country,'All countries')?></select><select name="type" data-auto-submit><?=option_tags($types,$type,'All aircraft types')?></select><button class="btn ink">Search</button></form></div><p class="muted">Showing <?=nfmt(count($list))?> of <?=nfmt($total)?> aircraft registration records.</p><div class="table-wrap"><table class="mini-table"><thead><tr><th>Registration</th><th>Aircraft type</th><th>ICAO / Operator</th><th>Age</th><th>Country</th></tr></thead><tbody><?php foreach($list as $f):?><tr><td><?=e($f['registration'])?></td><td><?=e($f['aircraft_type'])?></td><td><?=e($f['icao_code']?:$f['