<?php elseif($page==='regulatory'):$q=getv('q');$country=getv('country','all');$type=getv('type','all');$where=[];$params=[];if($country!=='all'){$where[]='r.country_code=?';$params[]=$country;}if($type!=='all'){$where[]='r.type=?';$params[]=$type;}if($q!==''){$where[]='(r.name LIKE ? OR r.regulator_name LIKE ? OR r.airline_iata LIKE ? OR r.airline_icao LIKE ? OR r.aoc_number LIKE ? OR r.authority LIKE ? OR r.city LIKE ?)';for($i=0;$i<7;$i++)$params[]='%'.$q.'%';}$w=$where?'WHERE '.implode(' AND ',$where):'';$list=rows("SELECT r.*, c.name country_name FROM regulatory_records r LEFT JOIN countries c ON c.code=r.country_code $w ORDER BY r.country_code,r.type,r.name LIMIT 300",$params);$types=rows("SELECT DISTINCT type value, type label FROM regulatory_records WHERE type IS NOT NULL AND type <> '' ORDER BY type");?><section class="view"><section class="section-head"><div><div class="eyebrow">Regulatory intelligence</div><h2>Regulatory</h2></div><p>Aviation authorities, AOC holders, regulators, contact rows and regulations loaded from country-level regulatory CSV files.</p></section><div class="filters panel"><form method="get"><input type="hidden" name="page" value="regulatory"><input name="q" value="<?=e($q)?>" placeholder="Search authority, AOC, airline…"><select name="country" data-auto-submit><?=option_tags(country_options(),$country,'All countries')?></select><select name="type" data-auto-submit><?=option_tags($types,$type,'All regulatory types')?></select><button class="btn ink">Search</button></form></div><div class="card-grid"><?php foreach($list as $r):?><article class="record-card" style="--h:<?=hue($r['name']?:$r['type'])?>"><div class="topline"><span class="chip gold"><?=e($r['type'])?></span><?=status_chip($r['status_bucket'])?></div><h3><?=e($r['name'])?></h3><p><?=e($r['country_name']?:$r['country_code'])?><?=$r['city']?' · '.e($r['city']):''?></p><div class="code-row"><?php if($r['aoc_number']):?><span class="chip">AOC <?=e($r['aoc_number'])?></span><?p